
"use client"

import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Mail, Gauge, Loader2 } from "lucide-react";
import { useRouter } from "next/navigation";
import Image from "next/image";
import { useAuth, useFirestore } from "@/firebase";
import { GoogleAuthProvider, OAuthProvider, signInWithPopup, signInAnonymously, type User } from "firebase/auth";
import { doc, getDoc, setDoc } from "firebase/firestore";
import { useState } from "react";
import { useToast } from "@/hooks/use-toast";

const GoogleIcon = () => (
  <svg viewBox="0 0 24 24" width="20" height="20" xmlns="http://www.w3.org/2000/svg">
    <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
    <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
    <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z" fill="#FBBC05"/>
    <path d="M12 5.38c1.62 0 3.06.56 4.21 1.66l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
  </svg>
);

const AppleIcon = () => (
  <svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor" xmlns="http://www.w3.org/2000/svg">
    <path d="M17.05 20.28c-.96.95-2.45 3.08-4.42 3.08-1.47 0-1.89-.88-3.65-.88-1.74 0-2.26.88-3.63.88-2.01 0-3.51-2.11-4.5-3.08-2.04-2-3.53-5.01-3.53-8.01 0-4.97 3.24-7.6 6.32-7.6 1.63 0 3.18 1.14 4.18 1.14 1 0 2.86-1.39 4.77-1.39 1.14 0 4.34.41 6.13 3.01-4.08 2.39-3.41 7.55 1.21 9.47-1.12 2.91-2.92 5.43-2.92 5.43zM12.03 5.07c.85-1.02 1.41-2.43 1.26-3.83-1.21.05-2.67.81-3.54 1.83-.78.9-.47 2.33-.28 3.73 1.34.11 2.56-.71 2.56-1.73z"/>
  </svg>
);

export default function Home() {
  const auth = useAuth();
  const db = useFirestore();
  const router = useRouter();
  const { toast } = useToast();
  const [loading, setLoading] = useState<string | null>(null);

  const initializeUserProfile = async (user: User) => {
    const userDocRef = doc(db, "users", user.uid);
    const userDoc = await getDoc(userDocRef);

    if (!userDoc.exists()) {
      await setDoc(userDocRef, {
        id: user.uid,
        username: user.displayName || user.email?.split('@')[0] || 'Shofer i Ri',
        city: 'Prishtinë',
        carBrand: 'E pa-identifikuar',
        carModel: 'E pa-identifikuar',
        horsepower: 0,
        modifications: 'Stock',
        profilePhotoUrl: user.photoURL || `https://picsum.photos/seed/${user.uid}/200/200`,
        followedUserIds: [],
        isPremium: false,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      });
    }
  };

  const handleGoogleSignIn = async () => {
    setLoading('google');
    try {
      const provider = new GoogleAuthProvider();
      const result = await signInWithPopup(auth, provider);
      await initializeUserProfile(result.user);
      router.push('/dashboard');
    } catch (error: any) {
      toast({
        variant: "destructive",
        title: "Dështoi hyrja",
        description: error.message || "Dështoi hyrja me Google. Sigurohuni që Google Auth është aktivizuar në Firebase Console.",
      });
    } finally {
      setLoading(null);
    }
  };

  const handleAppleSignIn = async () => {
    setLoading('apple');
    try {
      const provider = new OAuthProvider('apple.com');
      const result = await signInWithPopup(auth, provider);
      await initializeUserProfile(result.user);
      router.push('/dashboard');
    } catch (error: any) {
      toast({
        variant: "destructive",
        title: "Dështoi hyrja",
        description: error.message || "Dështoi hyrja me Apple. Sigurohuni që Apple Auth është aktivizuar në Firebase Console.",
      });
    } finally {
      setLoading(null);
    }
  };

  const handleGuestSignIn = async () => {
    setLoading('guest');
    try {
      const result = await signInAnonymously(auth);
      await initializeUserProfile(result.user);
      router.push('/dashboard');
    } catch (error: any) {
      toast({
        variant: "destructive",
        title: "Hyrja dështoi",
        description: error.message || "Dështoi hyrja si mysafir.",
      });
    } finally {
      setLoading(null);
    }
  };

  return (
    <div className="flex flex-col min-h-screen overflow-hidden p-6 gap-8">
      {/* Hero Section */}
      <div className="mt-12 space-y-4">
        <div className="flex items-center gap-2">
          <div className="w-10 h-10 bg-accent rounded-xl flex items-center justify-center neon-glow">
            <Gauge className="text-background w-6 h-6" />
          </div>
          <h1 className="text-2xl font-black tracking-tighter uppercase italic">
            DriveRank<span className="text-accent neon-text"> Kosovë</span>
          </h1>
        </div>
        <p className="text-muted-foreground text-sm font-medium leading-relaxed">
          Adhuruesit e makinave në Kosovë
        </p>
      </div>

      {/* Featured Car Glass Card */}
      <div className="relative h-64 w-full rounded-3xl overflow-hidden glass border-white/5 shadow-2xl group">
        <Image 
          src="https://picsum.photos/seed/bmw-main/1200/800" 
          alt="Makinë Sportive" 
          fill 
          className="object-cover opacity-60 group-hover:scale-105 transition-transform duration-700"
          data-ai-hint="sports car"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-background via-transparent to-transparent" />
        <div className="absolute bottom-4 left-4 right-4 flex justify-between items-end">
          <div>
            <Badge variant="outline" className="mb-2 bg-accent/10 border-accent/20 text-accent font-bold">GARA E FUNDIT</Badge>
            <h3 className="text-lg font-bold">BMW M4 CS</h3>
            <p className="text-xs text-muted-foreground">Prishtinë • 0-100 në 3.4s</p>
          </div>
          <div className="text-right">
            <div className="text-2xl font-black text-accent neon-text italic">#1</div>
            <div className="text-[10px] uppercase font-bold text-muted-foreground">Ranking</div>
          </div>
        </div>
      </div>

      {/* Auth Options */}
      <div className="space-y-4 mt-auto mb-8">
        <div className="space-y-3">
          <Button 
            variant="outline" 
            onClick={handleGoogleSignIn}
            disabled={!!loading}
            className="w-full h-14 rounded-2xl bg-white text-black hover:bg-white/90 border-none flex items-center gap-3 text-base font-bold"
          >
            {loading === 'google' ? <Loader2 className="w-5 h-5 animate-spin" /> : <GoogleIcon />}
            Vazhdo me Google
          </Button>
          <Button 
            variant="outline" 
            onClick={handleAppleSignIn}
            disabled={!!loading}
            className="w-full h-14 rounded-2xl bg-black text-white hover:bg-black/90 border-white/20 flex items-center gap-3 text-base font-bold"
          >
            {loading === 'apple' ? <Loader2 className="w-5 h-5 animate-spin" /> : <AppleIcon />}
            Vazhdo me Apple
          </Button>
          <div className="flex items-center gap-4 py-2">
            <div className="h-px flex-1 bg-white/10" />
            <span className="text-[10px] uppercase font-bold text-muted-foreground">Ose hyni si mysafir</span>
            <div className="h-px flex-1 bg-white/10" />
          </div>
          <Button 
            variant="default" 
            onClick={handleGuestSignIn}
            disabled={!!loading}
            className="w-full h-14 rounded-2xl bg-primary hover:bg-primary/80 flex items-center gap-3 text-base font-bold shadow-xl"
          >
            {loading === 'guest' ? <Loader2 className="w-5 h-5 animate-spin" /> : <Mail className="w-5 h-5" />}
            Fillim i Shpejtë (Mysafir)
          </Button>
        </div>
        
        <p className="text-center text-xs text-muted-foreground px-8">
          Duke u futur, ju pranoni <span className="text-accent underline">Kushtet e Shërbimit</span> dhe <span className="text-accent underline">Politikën e Privatësisë</span>.
        </p>
      </div>
    </div>
  );
}
